parameters.jsCode:
const items = $input.all();

// 1. Extract memories from RAG
const memories = items
  .map(item => item.json.content || item.json.raw_content)
  .filter(c => c && c.trim() !== "")
  .join(' | ');

// 2. Get current thought and embedding vector
const currentThought = $('Merge Streams').item.json.final_thought;
const currentVector = $('Generate Embeddings').item.json.embedding.values;

// 3. Get localized prompt and inject user data
const lang = $('Strict Entry (Brain)').item.json.context.language || 'es';
const promptData = $('Get Brain Prompts').first().json;
let fullPrompt = promptData[lang] || "";

// 4. Replace placeholders now that we have all the data
const historical = memories || "No previous history.";
fullPrompt = fullPrompt.replace('{{historical_context}}', historical);
fullPrompt = fullPrompt.replace('{{user_thought}}', currentThought);

return [{
  json: {
    final_thought: currentThought,
    historical_context: historical,
    embedding_vector: currentVector,
    final_prompt: fullPrompt
  }
}];

